// Sandbox-gated repairs — high-severity issues where a small code change is
// generated by Claude inside the existing sandbox component and (if green +
// diff ≤ 50 LOC + safe surface) opens a PR for the existing self-repair
// pipeline to merge.
//
// IMPORTANT: this layer DOES NOT modify lib/harness/self-repair/* or
// lib/harness/sandbox/*. It only DELEGATES to those modules. Both are
// read-only dependencies per the SCOPE CONTRACT.

import type { CheckResult, RepairContext, RepairResult } from '../types'

/**
 * Heuristic: which checks are eligible for code-fix-via-sandbox?
 * Today: only structural drift in agent/harness code surfaces fall here.
 * v2 ships the gate but no surfaces are wired — every call returns
 * `not_applicable` with reason. v2.1 will wire concrete surfaces.
 */
export function isSandboxGatedEligible(result: CheckResult): boolean {
  if (result.status !== 'fail') return false
  if (!result.severity) return false
  if (result.severity !== 'high' && result.severity !== 'critical') return false
  // Anything that's RLS, auth, schema, secrets — NEVER auto-PR
  // (matches existing self-repair pipeline AD2).
  const FORBIDDEN_KEYS = [
    'security.rls_coverage',
    'security.gitleaks',
    'security.dependabot_critical',
    'security.security_score_drop',
    'data.schema_drift',
  ]
  if (FORBIDDEN_KEYS.includes(result.key)) return false
  return false // v2: no surface wired yet — always escalate.
}

export async function attemptSandboxRepair(
  _result: CheckResult,
  ctx: RepairContext
): Promise<RepairResult> {
  if (ctx.observeOnly || ctx.dryRun) {
    return {
      outcome: 'not_applicable',
      evidence: { reason: ctx.dryRun ? 'dry_run' : 'observe_only' },
      resolved: false,
    }
  }
  // v2.1 will:
  //   1. Build a fix prompt from check evidence + recent commits.
  //   2. Call lib/harness/self-repair/drafter draftFix() (read-only delegate).
  //   3. Call lib/harness/sandbox/runtime runInSandbox() to apply + test.
  //   4. If green + diff <= 50 LOC + no forbidden surfaces, call
  //      lib/harness/self-repair/pr-opener openPR() with auto-merge label.
  //   5. Return outcome='sandbox_pr_opened', resolved=true.
  // v2: no surface wired — return not_applicable so the orchestrator
  // routes to escalate.
  return {
    outcome: 'not_applicable',
    evidence: {
      reason:
        'sandbox-gated repair surfaces not wired in v2. Logged in cross-window-suggestions for v2.1.',
    },
    resolved: false,
  }
}
